query:
-- Total de filas (caras)
SELECT COUNT(*) as total_caras FROM paradas;

-- Paradas físicas únicas por cobertizo_id
SELECT COUNT(DISTINCT cobertizo_id) as total_cobertizos_unicos FROM paradas;

-- Cobertizos con variantes A/B (misma base numérica)
SELECT COUNT(DISTINCT REGEXP_REPLACE(cobertizo_id, '[A-Za-z]+$', '')) as total_fisicas_estimado FROM paradas;

-- Ejemplos de cobertizos con múltiples variantes
SELECT cobertizo_id, COUNT(*) as caras FROM paradas GROUP BY cobertizo_id ORDER BY cobertizo_id LIMIT 20;

